        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != 128 {
            return;
        }
        self.data.write().insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut guard = self.data.write();
        let mut count = 0;
        for (id, vec) in vectors {
            if vec.len() == 128 {
                guard.insert(id, vec);
                count += 1;
            }
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if vector.len() != 128 || top_k == 0 {
            return vec![];
        }
        let data = self.data.read();
        let k = top_k as usize;
        let mut heap = std::collections::BinaryHeap::with_capacity(k + 1);
        for (id, v) in data.iter() {
            let dist = crate::distance::l2_distance(vector, v);
            heap.push(SearchResultHeap { id: *id, distance: dist });
            if heap.len() > k {
                heap.pop();
            }
        }
        let mut results: Vec<SearchResult> = heap.into_iter().map(|x| SearchResult { id: x.id, distance: x.distance }).collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
        results
    }
