#[derive(PartialEq, PartialOrd)]
struct SearchResultHeap {
    id: u64,
    distance: f64,
}

impl Eq for SearchResultHeap {}

impl Ord for SearchResultHeap {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        // Reverse ordering for max-heap so that largest distance is popped
        other.distance.partial_cmp(&self.distance).unwrap_or(std::cmp::Ordering::Equal)
    }
}

